    # Check for player names with sports context from the Ryder Cup article we saw
    sports_players = ['d-marco', 'riley', 'jay haas', 'steve flesh']

    # Check if this is a sports article
    is_sports = False

    # Check for sports indicators
    for indicator in sports_indicators:
