    elif 'football' in lower_title or 'football' in lower_desc:
        is_sports = True
    elif 'basketball' in lower_title or 'basketball' in lower_desc:
        is_sports = True
    elif 'tennis' in lower_title or 'tennis' in lower_desc:
        is_sports = True
    elif 'baseball' in lower_title or 'baseball' in lower_desc:
        is_sports = True
    elif 'hockey' in lower_title or 'hockey' in lower_desc:
        is_sports = True
    elif 'cricket' in lower_title or 'cricket' in lower_desc:
        is_sports = True

    if is_sports:
        sports_article = {
            'article_id': article_id,
            'title': title,
            'description': description,
            'description_length': len(description)
        }
        sports_articles.append(sports_article)

# Find the sports article with the longest description
if sports_articles:
    longest = max(sports_articles, key=lambda x: x['description_length'])

    result = {
        'title': longest['title'],
        'article_id': longest['article_id'],
        'description_length': longest['description_length'],
        'total_sports_found': len(sports_articles)
    }
else:
    result = {'error': 'No sports articles found'}

# Show top 10 sports articles by description length
top_10 = sorted(sports_articles, key=lambda x: x['description_length'], reverse=True)[:10]

print('__RESULT__:')
print(json.dumps({
    'answer': result.get('title'),
    'details': result,
    'top_10_sports': top_10
}, indent=2))"}

